    for (let j = 0; j &lt; n - i - 1; j++) {
      out.push({ type: "compare", arr: [...arr], i: j, j: j+1, sortedBound });

      if (arr[j] &gt; arr[j + 1]) {
        let temp = arr[j];
        arr[j] = arr[j + 1];
        arr[j + 1] = temp;
        swapped = true;

        out.push({ type: "swap", arr: [...arr], i: j, j: j+1, sortedBound });
      }
    }
    sortedBound = n - i - 1;
    if (!swapped) break; 
  }

  out.push({ type: "done", arr: [...arr], i: null, j: null, sortedBound: 0 });
  return out;
}







